package par2

import (
	"crypto/md5"
	"hash/crc32"
	"os"
	"path/filepath"
	"testing"
)

// loadFixture concatenates the index and recovery PAR2 files generated by
// par2cmdline (see testdata/) and parses them.
func loadFixture(t *testing.T) (*RecoverySet, []byte) {
	t.Helper()
	var all []byte
	for _, name := range []string{"recovery.par2", "recovery.vol0+8.par2"} {
		b, err := os.ReadFile(filepath.Join("testdata", name))
		if err != nil {
			t.Fatalf("read fixture %s: %v", name, err)
		}
		all = append(all, b...)
	}
	rs, err := Parse(all)
	if err != nil {
		t.Fatalf("Parse: %v", err)
	}
	data, err := os.ReadFile(filepath.Join("testdata", "data.bin"))
	if err != nil {
		t.Fatalf("read data.bin: %v", err)
	}
	return rs, data
}

// sliceOf returns input slice i of data, zero-padded to sliceSize.
func sliceOf(data []byte, i int, sliceSize int) []byte {
	s := make([]byte, sliceSize)
	off := i * sliceSize
	if off < len(data) {
		copy(s, data[off:])
	}
	return s
}

func TestParseFixtureStructure(t *testing.T) {
	rs, data := loadFixture(t)

	if rs.SliceSize != 4096 {
		t.Errorf("SliceSize = %d, want 4096", rs.SliceSize)
	}
	if len(rs.RecoveryFileIDs) != 1 {
		t.Fatalf("recovery files = %d, want 1", len(rs.RecoveryFileIDs))
	}
	fid := rs.RecoveryFileIDs[0]
	fd := rs.Files[fid]
	if fd == nil {
		t.Fatal("no FileDesc for recovery file")
	}
	if fd.Length != uint64(len(data)) || fd.Name != "data.bin" {
		t.Errorf("FileDesc = {len:%d name:%q}, want {len:%d name:data.bin}", fd.Length, fd.Name, len(data))
	}
	// Whole-file MD5 must match.
	if md5.Sum(data) != fd.MD5 {
		t.Error("FileDesc whole-file MD5 mismatch")
	}

	nSlices := (len(data) + 4095) / 4096
	if got := len(rs.SliceCRCs[fid]); got != nSlices {
		t.Errorf("slice checksums = %d, want %d", got, nSlices)
	}
	if len(rs.Recovery) != 8 {
		t.Errorf("recovery slices = %d, want 8", len(rs.Recovery))
	}
}

// TestSliceChecksumsMatchData validates that the per-slice MD5/CRC32 we parsed
// from the IFSC packet match slices computed from the real data — confirming
// both the parser and our slicing/zero-padding convention.
func TestSliceChecksumsMatchData(t *testing.T) {
	rs, data := loadFixture(t)
	fid := rs.RecoveryFileIDs[0]
	sums := rs.SliceCRCs[fid]
	ss := int(rs.SliceSize)

	for i, want := range sums {
		s := sliceOf(data, i, ss)
		if md5.Sum(s) != want.MD5 {
			t.Errorf("slice %d MD5 mismatch", i)
		}
		if got := crc32.ChecksumIEEE(s); got != want.CRC32 {
			t.Errorf("slice %d CRC32 = %08x, want %08x", i, got, want.CRC32)
		}
	}
}

// TestRecoveryExponentZeroIsXOR is the keystone validation: a PAR2 recovery
// slice with exponent 0 has coefficient base^0 = 1 for every input block, so it
// must equal the GF sum (XOR) of all input slices. Matching the real
// par2cmdline output proves the field arithmetic, parser, and slice handling
// are all consistent with the spec — without yet needing the RS base constants.
func TestRecoveryExponentZeroIsXOR(t *testing.T) {
	rs, data := loadFixture(t)
	ss := int(rs.SliceSize)
	nSlices := (len(data) + ss - 1) / ss

	var exp0 *RecoverySlice
	for i := range rs.Recovery {
		if rs.Recovery[i].Exponent == 0 {
			exp0 = &rs.Recovery[i]
			break
		}
	}
	if exp0 == nil {
		t.Fatal("no recovery slice with exponent 0 in fixture")
	}

	want := make([]byte, ss)
	for i := 0; i < nSlices; i++ {
		xorInto(want, sliceOf(data, i, ss))
	}

	for i := range want {
		if want[i] != exp0.Data[i] {
			t.Fatalf("exponent-0 recovery mismatch at byte %d: xor=%02x par2=%02x", i, want[i], exp0.Data[i])
		}
	}
}
